    public int numberOfStableArrays(int zero, int one, int limit) {
        int[][][] dp = new int[zero + 1][one + 1][2];
        for (int z = 1; z <= zero; ++z) {
            if (z <= limit) dp[z][0][0] = 1;
        }
        for (int o = 1; o <= one; ++o) {
            if (o <= limit) dp[0][o][1] = 1;
        }

        int[][] prefix0 = new int[zero + 2][one + 1];
        int[][] prefix1 = new int[zero + 1][one + 2];

        for (int z = 0; z <= zero; ++z) {
            for (int o = 0; o <= one; ++o) {
                if (z > 0) {
                    int lo = Math.max(0, o - limit);
                    int hi = o;
                    int sum = (prefix0[z - 1][hi] - (lo > 0 ? prefix0[z - 1][lo - 1] : 0) + MOD) % MOD;
                    dp[z][o][0] = sum;
                }
                if (o > 0) {
                    int lo = Math.max(0, z - limit);
                    int hi = z;
                    int sum = (prefix1[hi][o - 1] - (lo > 0 ? prefix1[lo - 1][o - 1] : 0) + MOD) % MOD;
                    dp[z][o][1] = sum;
                }
                prefix0[z][o] = ((o > 0 ? prefix0[z][o - 1] : 0) + dp[z][o][0]) % MOD;
                prefix1[z][o] = ((z > 0 ? prefix1[z - 1][o] : 0) + dp[z][o][1]) % MOD;
            }
        }
        return (dp[zero][one][0] + dp[zero][one][1]) % MOD;
